action.old_str:
llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  if (!obj || !obj->head) {
    return nullptr;
  }
  auto& irb = *mCurIrb;
  auto* callee = self(obj->head);

  if (!callee) {
    return nullptr;
  }

  std::vector<llvm::Value*> args;
  for (auto* arg : obj->args) {
    auto* a = self(arg);
    if (a) {
      args.push_back(a);
    }
  }

  // Get function from module
  auto* func = mMod.getFunction(obj->head->name);
  if (!func) {
    return nullptr;
  }

  return irb.CreateCall(func, args);
}

action.new_str:
llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  if (!obj || !obj->head) {
    return nullptr;
  }
  auto& irb = *mCurIrb;

  // Get function name from head if it's a DeclRefExpr
  std::string funcName;
  if (auto* ref = obj->head->dcst<DeclRefExpr>()) {
    funcName = ref->decl->name;
  }

  if (funcName.empty()) {
    return nullptr;
  }

  std::vector<llvm::Value*> args;
  for (auto* arg : obj->args) {
    auto* a = self(arg);
    if (a) {
      args.push_back(a);
    }
  }

  // Get function from module
  auto* func = mMod.getFunction(funcName);
  if (!func) {
    return nullptr;
  }

  return irb.CreateCall(func, args);
}

